cURLPython (Requests)JavaScript (Octokit) <pre><code>curl -L \
  -X POST \
  -H "Accept: application/vnd.github+json" \
  -H "Authorization: Bearer &lt;YOUR-TOKEN&gt;" \
  https://api.github.com/app/installations/{installation_id}/access_tokens \
  -d '{
  "repositories": [
    "&lt;string&gt;",
    "&lt;string&gt;"
  ],
  "repository_ids": [
    "&lt;integer&gt;",
    "&lt;integer&gt;"
  ],
  "permissions": {
    "contents": "&lt;string&gt;",
    "issues": "&lt;string&gt;",
    "deployments": "&lt;string&gt;",
    "single_file": "&lt;string&gt;",
    "def_not_a_repo": "&lt;string&gt;"
  }
}'
</code></pre> <pre><code>import requests

headers = {
  'Accept': 'application/vnd.github+json',
  'Authorization': 'Bearer &lt;YOUR-TOKEN&gt;'
}

import json

data = {
  "repositories": [
    "&lt;string&gt;",
    "&lt;string&gt;"
  ],
  "repository_ids": [
    "&lt;integer&gt;",
    "&lt;integer&gt;"
  ],
  "permissions": {
    "contents": "&lt;string&gt;",
    "issues": "&lt;string&gt;",
    "deployments": "&lt;string&gt;",
    "single_file": "&lt;string&gt;",
    "def_not_a_repo": "&lt;string&gt;"
  }
}

response = requests.post('https://api.github.com/app/installations/{installation_id}/access_tokens', headers=headers, data=json.dumps(data))
print(response.json())
</code></pre> <pre><code>const { Octokit } = require("@octokit/rest");
const octokit = new Octokit({
  auth: 'YOUR-TOKEN'
});

await octokit.request('POST /app/installations/{installation_id}/access_tokens', {
  headers: {
    'X-GitHub-Api-Version': '2022-11-28'
  },
  ...{
    "repositories": [
      "&lt;string&gt;",
      "&lt;string&gt;"
    ],
    "repository_ids": [
      "&lt;integer&gt;",
      "&lt;integer&gt;"
    ],
    "permissions": {
      "contents": "&lt;string&gt;",
      "issues": "&lt;string&gt;",
      "deployments": "&lt;string&gt;",
      "single_file": "&lt;string&gt;",
      "def_not_a_repo": "&lt;string&gt;"
    }
  }
});
</code></pre>

